//===============================================================================================================================================================================================================

#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <stdio.h>
#include <cuda.h>
#include <cuda_runtime.h>

extern "C" {
#include "../AVI/avilib.h"
#include "../AVI/avimod.h"
}

#define fp float
#define ENDO_POINTS 20
#define EPI_POINTS 31
#define ALL_POINTS 51

typedef struct public_struct{
	int tSize;
	int sSize;
	int maxMove;
	fp alpha;

	int endoPoints;
	int d_endo_mem;
	int* d_endoRow;
	int* d_endoCol;
	int* d_tEndoRowLoc;
	int* d_tEndoColLoc;
	fp* d_endoT;

	int epiPoints;
	int d_epi_mem;
	int* d_epiRow;
	int* d_epiCol;
	int* d_tEpiRowLoc;
	int* d_tEpiColLoc;
	fp* d_epiT;

	int allPoints;

	avi_t* d_frames;
	int frames;
	int frame_no;
	fp* d_frame;
	int frame_rows;
	int frame_cols;
	int frame_elem;
	int frame_mem;

	int in2_rows;
	int in2_cols;
	int in2_elem;
	int in2_mem;

	int in_mod_rows;
	int in_mod_cols;
	int in_mod_elem;
	int in_mod_mem;

	int ioffset;
	int joffset;

	int conv_rows;
	int conv_cols;
